import React from "react";
import { Chip, Stack, Typography, Box } from "@mui/material";

const skills = [
  { name: "HTML", emoji: "🌐", color: "primary" },
  { name: "CSS", emoji: "🎨", color: "secondary" },
  { name: "JavaScript", emoji: "⚡", color: "success" },
  { name: "TypeScript", emoji: "🛠️", color: "info" },
  { name: "React", emoji: "⚛️", color: "primary" },
  { name: "React Native", emoji: "📱", color: "secondary" },
  { name: "Django", emoji: "🐍", color: "success" },
  { name: "Python", emoji: "🐍", color: "info" },
  { name: "Azure", emoji: "☁️", color: "primary" },
  { name: "Share Hosting", emoji: "📡", color: "secondary" },
  { name: "Digital Ocean", emoji: "🌊", color: "success" },
  { name: "Mac", emoji: "🍏", color: "info" },
  { name: "Windows", emoji: "🖥️", color: "primary" },
  { name: "Linux", emoji: "🐧", color: "secondary" }
];

export default function Skills() {
  return (
    <Box
      sx={{
        textAlign: "center",
        bgcolor: "#121212",
        color: "white",
        py: 5,
        px: 2,
        borderRadius: 2
      }}
    >
      <Typography variant="h4" gutterBottom>
        💻 My Skills
      </Typography>
      <Stack
        direction="row"
        spacing={1}
        useFlexGap
        flexWrap="wrap"
        justifyContent="center"
      >
        {skills.map((skill, index) => (
          <Chip
            key={index}
            label={`${skill.emoji} ${skill.name}`}
            color={skill.color}
            sx={{
              fontSize: "16px",
              fontWeight: "bold",
              p: 1.2,
              cursor: "pointer",
              "&:hover": {
                opacity: 0.8
              }
            }}
          />
        ))}
      </Stack>
    </Box>
  );
}
